// ============================================================
// HydraNet - Team Leader API Route
// Manage team leader assignment with role synchronization
// ============================================================

import { NextRequest, NextResponse } from 'next/server'
import prisma from '@/lib/prisma'

interface RouteParams {
  params: Promise<{ id: string }>
}

// GET /api/teams/[id]/leader - Get team leader info
export async function GET(request: NextRequest, { params }: RouteParams) {
  try {
    const { id } = await params

    const team = await prisma.team.findUnique({
      where: { id },
      include: {
        leader: {
          select: { id: true, name: true, email: true, phone: true, role: true, status: true },
        },
        branch: {
          select: { id: true, name: true, utilityId: true, dmaId: true },
        },
      },
    })

    if (!team) {
      return NextResponse.json({ error: 'Team not found' }, { status: 404 })
    }

    // Get eligible team leaders (engineers from same branch/DMA, active, in this team or no team)
    const eligibleLeaders = await prisma.engineer.findMany({
      where: {
        branchId: team.branchId,
        dmaId: team.dmaId,
        status: 'active',
        OR: [
          { teamId: null },
          { teamId: id },
        ],
      },
      select: {
        id: true,
        name: true,
        email: true,
        phone: true,
        role: true,
        status: true,
        teamId: true,
      },
      orderBy: { name: 'asc' },
    })

    return NextResponse.json({
      leader: team.leader,
      eligibleLeaders,
      team: {
        id: team.id,
        name: team.name,
        branchId: team.branchId,
        branchName: team.branch.name,
        dmaId: team.dmaId,
      },
    })
  } catch (error) {
    console.error('Error fetching team leader:', error)
    return NextResponse.json({ error: 'Failed to fetch team leader' }, { status: 500 })
  }
}

// PUT /api/teams/[id]/leader - Assign team leader
export async function PUT(request: NextRequest, { params }: RouteParams) {
  try {
    const { id } = await params
    const data = await request.json()
    const { engineerId } = data

    if (!engineerId) {
      return NextResponse.json({ error: 'Engineer ID is required' }, { status: 400 })
    }

    // Check if team exists
    const team = await prisma.team.findUnique({
      where: { id },
      include: {
        leader: { select: { id: true } },
        branch: { select: { id: true, utilityId: true, dmaId: true } },
      },
    })

    if (!team) {
      return NextResponse.json({ error: 'Team not found' }, { status: 404 })
    }

    // Check if the engineer exists and is eligible
    const engineer = await prisma.engineer.findUnique({
      where: { id: engineerId },
    })

    if (!engineer) {
      return NextResponse.json({ error: 'Engineer not found' }, { status: 404 })
    }

    // Validate eligibility
    if (engineer.branchId !== team.branchId) {
      return NextResponse.json(
        { error: 'Engineer must be from the same branch as the team' },
        { status: 400 }
      )
    }

    if (engineer.dmaId !== team.dmaId) {
      return NextResponse.json(
        { error: 'Engineer must be from the same DMA as the team' },
        { status: 400 }
      )
    }

    if (engineer.status !== 'active') {
      return NextResponse.json(
        { error: 'Engineer must be active' },
        { status: 400 }
      )
    }

    // If engineer is in another team, they can't be leader of this team
    if (engineer.teamId && engineer.teamId !== id) {
      return NextResponse.json(
        { error: 'Engineer is already a member of another team' },
        { status: 400 }
      )
    }

    // Use transaction for atomic updates
    const result = await prisma.$transaction(async (tx) => {
      // If there's an existing leader, demote them to engineer
      if (team.leaderId && team.leaderId !== engineerId) {
        await tx.engineer.update({
          where: { id: team.leaderId },
          data: { role: 'engineer' },
        })
      }

      // Add engineer to team if not already a member
      if (!engineer.teamId) {
        await tx.engineer.update({
          where: { id: engineerId },
          data: { teamId: id, role: 'team_leader' },
        })
      } else {
        // Just update the role if already in team
        await tx.engineer.update({
          where: { id: engineerId },
          data: { role: 'team_leader' },
        })
      }

      // Update team's leader reference
      return await tx.team.update({
        where: { id },
        data: { leaderId: engineerId },
        include: {
          branch: { select: { id: true, name: true, utilityId: true } },
          dma: { select: { id: true, name: true } },
          leader: { select: { id: true, name: true, email: true, role: true, status: true } },
          engineers: { select: { id: true, name: true, email: true, role: true, status: true } },
        },
      })
    })

    return NextResponse.json({
      ...result,
      branchName: result.branch.name,
      dmaName: result.dma.name,
      utilityId: result.branch.utilityId,
      leaderName: result.leader?.name,
      memberCount: result.engineers.length,
      engineerIds: result.engineers.map(e => e.id),
    })
  } catch (error) {
    console.error('Error assigning team leader:', error)
    return NextResponse.json({ error: 'Failed to assign team leader' }, { status: 500 })
  }
}

// DELETE /api/teams/[id]/leader - Remove team leader
export async function DELETE(request: NextRequest, { params }: RouteParams) {
  try {
    const { id } = await params

    // Check if team exists
    const team = await prisma.team.findUnique({
      where: { id },
      include: {
        leader: { select: { id: true, name: true } },
      },
    })

    if (!team) {
      return NextResponse.json({ error: 'Team not found' }, { status: 404 })
    }

    if (!team.leaderId) {
      return NextResponse.json({ error: 'No team leader assigned' }, { status: 400 })
    }

    // Store leader ID for use in transaction
    const currentLeaderId = team.leaderId

    // Use transaction for atomic updates
    const result = await prisma.$transaction(async (tx) => {
      // Update the leader's role back to engineer (keep them in team)
      await tx.engineer.update({
        where: { id: currentLeaderId },
        data: { role: 'engineer' },
      })

      // Remove leader reference from team
      return await tx.team.update({
        where: { id },
        data: { leaderId: null },
        include: {
          branch: { select: { id: true, name: true, utilityId: true } },
          dma: { select: { id: true, name: true } },
          leader: { select: { id: true, name: true, email: true, role: true } },
          engineers: { select: { id: true, name: true, email: true, role: true, status: true } },
        },
      })
    })

    return NextResponse.json({
      branchName: result.branch.name,
      dmaName: result.dma.name,
      utilityId: result.branch.utilityId,
      ...(result.leader?.name ? { leaderName: result.leader.name } : {}),
      memberCount: result.engineers.length,
      engineerIds: result.engineers.map(e => e.id),
      message: 'Team leader removed successfully',
    })
  } catch (error) {
    console.error('Error removing team leader:', error)
    return NextResponse.json({ error: 'Failed to remove team leader' }, { status: 500 })
  }
}